import axios from 'axios';

const API_BASE = 'http://localhost:8080/area/api';

const api = axios.create({
  baseURL: API_BASE,
  headers: {
    'Content-Type': 'application/json'
  }
});

// Перехватчик для добавления токена
api.interceptors.request.use(config => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = token;
  }
  return config;
});

export const authAPI = {
  login: async (username, password) => {
    try {
      const response = await api.post('/login', { username, password });
      if (response.data.token) {
        localStorage.setItem('token', response.data.token);
        return { success: true };
      }
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.message || 'Ошибка авторизации'
      };
    }
  },

  logout: async () => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        await api.post('/logout', {}, {
          headers: { Authorization: token }
        });
      } catch (error) {
        // Игнорируем ошибки при логауте
      }
    }
    localStorage.removeItem('token');
  }
};

export const pointAPI = {
  checkPoint: async (x, y, r) => {
    try {
      const response = await api.post('/check', { x, y, r });
      return { success: true, data: response.data };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.message || 'Ошибка проверки точки'
      };
    }
  },

  getResults: async () => {
    try {
      const response = await api.get('/results');
      return { success: true, data: response.data };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.message || 'Ошибка загрузки результатов'
      };
    }
  },

  clearResults: async () => {
    try {
      await api.delete('/results');
      return { success: true };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.message || 'Ошибка очистки'
      };
    }
  }
};

// Проверка токена
export const checkAuth = async (token) => {
  try {
    // Можно сделать специальный endpoint /api/validate-token
    // или просто попробовать получить результаты
    const response = await api.get('/results', {
      headers: { Authorization: token }
    });
    return response.status === 200;
  } catch {
    return false;
  }
};

export default api;
